To professionally save the generated PDF to Google Drive and link it in your Google Sheet **without modifying your React application code**, you need to update the logic inside your **Google Apps Script**.

Here is the professional implementation code.

### Step 1: Open your Google Apps Script
1. Open your Google Sheet.
2. Go to **Extensions** > **Apps Script**.

### Step 2: Update the Script
Copy and paste the following function at the bottom of your script file. This function professionally handles directory management (creating a folder if it doesn't exist), binary decoding, and file linking.

```javascript
/**
 * Professionally saves a Base64 PDF to Drive and links it in the Sheet.
 * @param {Sheet} sheet - The active sheet object.
 * @param {string} base64Data - The raw base64 PDF string.
 * @param {string} recordId - Unique ID for the filename.
 * @param {string} truckNo - Truck number for the filename.
 */
function processAndSavePDF(sheet, base64Data, recordId, truckNo) {
  try {
    // 1. Clean the Base64 String (remove metadata prefix if present)
    var cleanBase64 = base64Data.replace(/^data:application\/pdf;base64,/, "");

    // 2. Create the PDF Blob
    var decodedBytes = Utilities.base64Decode(cleanBase64);
    var timestamp = Utilities.formatDate(new Date(), Session.getScriptTimeZone(), "yyyy-MM-dd_HHmm");
    var fileName = "Report_" + truckNo + "_" + timestamp + ".pdf";
    var blob = Utilities.newBlob(decodedBytes, MimeType.PDF, fileName);

    // 3. Organization: Get or Create 'SafetyCheck Reports' Folder
    var folderName = "SafetyCheck Reports";
    var folders = DriveApp.getFoldersByName(folderName);
    var folder = folders.hasNext() ? folders.next() : DriveApp.createFolder(folderName);

    // 4. Save File to Drive
    var file = folder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW); // Optional: Make viewable via link
    var fileUrl = file.getUrl();

    // 5. Save Link to Sheet
    // We append the link to the very last column of the newly created row
    var lastRow = sheet.getLastRow();
    var lastCol = sheet.getLastColumn();

    // Check if the last header is "PDF Report". If not, add it.
    var lastHeader = sheet.getRange(1, lastCol).getValue();
    var targetCol = lastCol;

    if (lastHeader !== "PDF Report") {
      targetCol = lastCol + 1;
      sheet.getRange(1, targetCol).setValue("PDF Report").setFontWeight("bold");
    }

    // Write the clickable URL
    sheet.getRange(lastRow, targetCol).setValue(fileUrl);

    return file;

  } catch (e) {
    Logger.log("PDF Save Error: " + e.toString());
    // Fallback: Write error to sheet so you know it failed
    sheet.getRange(sheet.getLastRow(), sheet.getLastColumn() + 1).setValue("PDF Error: " + e.toString());
  }
}
```

