To professionally automatically email the generated PDF to users based on their notification settings **without modifying your React App**, you need to add specific logic to your **Google Apps Script**.

This solution assumes your App is already configured to send the PDF as a Base64 string (as discussed in the previous step regarding saving to Drive).

Here is the professional implementation for your backend script.

### Step 1: Open Google Apps Script
1.  Open your Google Sheet.
2.  Go to **Extensions** > **Apps Script**.

### Step 2: Add the Email Logic
Copy and paste the following professional code block at the **bottom** of your script file. This code handles user lookup, preference filtering, HTML email construction, and binary attachment handling.

```javascript
/**
 * ------------------------------------------------------------------
 * PROFESSIONAL EMAIL NOTIFICATION SYSTEM
 * ------------------------------------------------------------------
 */

function sendEmailWithPDF(ss, sheetName, rowData, pdfBase64) {
  try {
    // 1. Get Recipients based on User Preferences
    var recipients = getTargetRecipients(ss, sheetName);
    if (recipients.length === 0) {
      Logger.log("No users have enabled notifications for " + sheetName);
      return; 
    }

    // 2. Prepare the PDF Attachment
    var cleanBase64 = pdfBase64.replace(/^data:application\/pdf;base64,/, "");
    var decodedBytes = Utilities.base64Decode(cleanBase64);
    var truckNo = rowData[2] || "Unknown-Vehicle";
    var dateStr = Utilities.formatDate(new Date(), Session.getScriptTimeZone(), "dd MMM yyyy");
    var fileName = sheetName + "_Inspection_" + truckNo + "_" + dateStr + ".pdf";
    var pdfBlob = Utilities.newBlob(decodedBytes, MimeType.PDF, fileName);

    // 3. Extract Key Details for the Email Body
    var details = extractDetails(sheetName, rowData);

    // 4. Construct Professional HTML Template
    var htmlBody = 
      '<div style="font-family: Arial, sans-serif; max-width: 600px; color: #333;">' +
        '<div style="background-color: #064e3b; padding: 20px; text-align: center; color: white; border-radius: 8px 8px 0 0;">' +
          '<h2 style="margin: 0;">New Inspection Submitted</h2>' +
          '<p style="margin: 5px 0 0 0; font-size: 12px; opacity: 0.8;">' + sheetName + ' Module</p>' +
        '</div>' +
        '<div style="border: 1px solid #ddd; border-top: none; padding: 20px; border-radius: 0 0 8px 8px;">' +
          '<p><strong>Vehicle:</strong> ' + details.truck + '</p>' +
          '<p><strong>Inspector:</strong> ' + details.inspector + '</p>' +
          '<p><strong>Rating:</strong> ' + details.rating + '/5 ' + getRatingLabel(details.rating) + '</p>' +
          '<p><strong>Remarks:</strong><br/><em>' + (details.remarks || "No remarks provided") + '</em></p>' +
          '<hr style="border: 0; border-top: 1px solid #eee; margin: 20px 0;">' +
          '<p style="font-size: 13px; color: #666;">The full inspection report is attached to this email as a PDF.</p>' +
        '</div>' +
        '<div style="text-align: center; margin-top: 15px; font-size: 11px; color: #aaa;">' +
          'Generated by SafetyCheck Pro System' +
        '</div>' +
      '</div>';

    // 5. Send the Email
    MailApp.sendEmail({
      to: recipients.join(","),
      subject: "📢 Inspection Report: " + details.truck + " (" + sheetName + ")",
      htmlBody: htmlBody,
      attachments: [pdfBlob]
    });

    Logger.log("Email sent to: " + recipients.join(","));

  } catch (e) {
    Logger.log("Email Error: " + e.toString());
  }
}

// --- HELPER FUNCTIONS ---

function getTargetRecipients(ss, moduleName) {
  var usersSheet = ss.getSheetByName('Users');
  if (!usersSheet) return [];

  var data = usersSheet.getDataRange().getValues();
  var emails = [];

  // Skip Header (row 0), iterate data
  for (var i = 1; i < data.length; i++) {
    var username = data[i][0]; // Assuming username is email, if not, you might need an Email column
    var prefsJson = data[i][6]; // Column G is Preferences

    // If username looks like an email, check prefs
    if (username && username.indexOf('@') > -1) {
      try {
        var prefs = JSON.parse(prefsJson || "{}");

        // Check Global Switch
        if (prefs.emailNotifications === true) {
          // Check Specific Module Switch
          var shouldSend = false;
          if (moduleName === 'General' && prefs.notifyGeneral) shouldSend = true;
          if (moduleName === 'Petroleum' && prefs.notifyPetroleum) shouldSend = true;
          if (moduleName === 'Acid' && prefs.notifyAcid) shouldSend = true;

          if (shouldSend) {
            emails.push(username);
          }
        }
      } catch (e) {
        // Ignore JSON parse errors
      }
    }
  }

  // Always include the Manager Email from System Settings as a fallback/CC
  var settingsSheet = ss.getSheetByName('System_Settings');
  if (settingsSheet && settingsSheet.getLastRow() > 1) {
     var managerEmail = settingsSheet.getRange(settingsSheet.getLastRow(), 2).getValue();
     if (managerEmail && managerEmail.indexOf('@') > -1 && emails.indexOf(managerEmail) === -1) {
       emails.push(managerEmail);
     }
  }

  return emails;
}

function extractDetails(sheetName, row) {
  // Mapping indices based on sheet structure
  if (sheetName === 'General') {
    return { truck: row[2], inspector: row[4], rating: row[8], remarks: row[9] };
  } else {
    // Petroleum / Acid usually have slightly different structures
    // Truck(2), Inspector(7), Rating(9), Remarks(10)
    return { truck: row[2], inspector: row[7], rating: row[9], remarks: row[10] };
  }
}

function getRatingLabel(rating) {
  var r = Number(rating);
  if (r >= 4) return '<span style="color:green; font-weight:bold;">(PASS)</span>';
  if (r === 3) return '<span style="color:orange; font-weight:bold;">(WARNING)</span>';
  return '<span style="color:red; font-weight:bold;">(CRITICAL)</span>';
}
```

