    GmailApp.sendEmail(recipients.join(","), subject, "", {
      htmlBody: htmlBody,
      attachments: [pdfBlob],

      // PROFESSIONAL SETTINGS
      name: "SafetyCheck Support",           // The name people see in their inbox
      from: "support@sallychanza.com",       // <--- CHANGE THIS to any email in your screenshot
